"use client";

import { useState } from "react";
import DisclaimerBanner from "../../components/DisclaimerBanner";

type ChatMessage = {
  role: "user" | "assistant";
  content: string;
  citations?: Array<{ code: string; articleNumber: string }>;
};

const ChatPage = () => {
  const [input, setInput] = useState("");
  const [messages, setMessages] = useState<ChatMessage[]>([]);
  const [loading, setLoading] = useState(false);

  const sendMessage = async () => {
    if (!input.trim()) {
      return;
    }

    const userMessage: ChatMessage = { role: "user", content: input };
    setMessages((prev) => [...prev, userMessage]);
    setInput("");
    setLoading(true);

    try {
      const response = await fetch("/api/chat", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ question: userMessage.content })
      });

      if (!response.ok) {
        throw new Error("Chat request failed");
      }

      const data = await response.json();
      const assistantMessage: ChatMessage = {
        role: "assistant",
        content: data.answer || "Unable to respond.",
        citations: data.citations || []
      };

      setMessages((prev) => [...prev, assistantMessage]);
    } catch (error) {
      setMessages((prev) => [
        ...prev,
        {
          role: "assistant",
          content: "Unable to answer right now. Please try again later."
        }
      ]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="section space-y-6">
      <div>
        <h1 className="text-3xl font-semibold">AI legal chat / استشارة ذكية</h1>
        <p className="text-slate-600">
          Ask a question. AI-Mizan will cite relevant law articles or decline if
          none match.
        </p>
      </div>

      <DisclaimerBanner />

      <div className="space-y-4">
        {messages.map((message, index) => (
          <div
            key={index}
            className={`rounded-2xl p-4 ${
              message.role === "user"
                ? "bg-emerald-50 text-emerald-900"
                : "bg-white text-slate-800"
            }`}
          >
            <p className="whitespace-pre-line">{message.content}</p>
            {message.citations && message.citations.length > 0 && (
              <div className="mt-3 text-xs text-slate-500">
                Citations: {message.citations.map((c) => `${c.code}:${c.articleNumber}`).join(", ")}
              </div>
            )}
          </div>
        ))}
      </div>

      <div className="flex flex-col gap-3 md:flex-row">
        <textarea
          value={input}
          onChange={(event) => setInput(event.target.value)}
          placeholder="Type your question in Arabic, French, or Darija..."
          className="min-h-[100px] flex-1 rounded-2xl border border-slate-200 p-4"
        />
        <button
          onClick={sendMessage}
          disabled={loading}
          className="rounded-2xl bg-emerald-600 px-6 py-3 text-white"
        >
          {loading ? "Sending..." : "Send"}
        </button>
      </div>
    </div>
  );
};

export default ChatPage;
